sql:
SELECT DISTINCT component_type
FROM design_components
WHERE status = 'active';

SELECT tool_name, version
FROM design_tools
WHERE status = 'active';

external_knowledge:
; The term 'design component' refers to individual parts of a larger system, which can be modules or IP cores; 
; 'test result' includes information about whether the test on the component was successful or not, such as 'pass' or 'fail'; 
; The project hierarchy is constructed to show the management structure of the projects.

sql:
SELECT COUNT(*) AS successful_imports
FROM file_imports
WHERE imported_by = 1 AND status = 'success';

SELECT COUNT(*) AS active_revisions_count
FROM design_revisions
WHERE component_id = 1 AND status = 'active';

SELECT file_name
FROM file_imports
WHERE status = 'success';
